import React from 'react';

const ResizeHandle = ({ onMouseDown, isVertical = true, isActive = false }) => {
  return (
    <div
      className={`resize-handle ${isVertical ? 'resize-handle--vertical' : 'resize-handle--horizontal'} ${isActive ? 'resize-handle--active' : ''}`}
      onMouseDown={onMouseDown}
    >
      <div className="resize-handle__indicator">
        <div className="resize-handle__dots">
          <span></span>
          <span></span>
          <span></span>
        </div>
      </div>
    </div>
  );
};

export default ResizeHandle;
